import { useMemo, useState } from 'react';
import { BrowserRouter as Router, Link, Route, Routes, useNavigate, useParams } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';
import { database } from './data';

const studentDetailsById = database.student_details.reduce((map, item) => {
  map[item.studentId] = item;
  return map;
}, {});

const evaluationsByStudent = database.evaluations.reduce((map, item) => {
  if (!map[item.studentId]) map[item.studentId] = [];
  map[item.studentId].push(item);
  return map;
}, {});

function HomePage() {
  const [searchText, setSearchText] = useState('');
  const [subjects, setSubjects] = useState(database.subjects);
  const [selectedSubject, setSelectedSubject] = useState('');
  const [newSubjectId, setNewSubjectId] = useState('');
  const [newSubjectName, setNewSubjectName] = useState('');

  const filteredStudents = useMemo(() => {
    const query = searchText.trim().toLowerCase();
    return database.students
      .filter((student) => {
        const matchesSearch = student.name.toLowerCase().includes(query);
        const matchesSubject = selectedSubject
          ? database.students_subjetcs.some(
              (entry) => entry.studentId === student.studentId && entry.subjectId === selectedSubject
            )
          : true;
        return matchesSearch && matchesSubject;
      })
      .map((student) => ({
        ...student,
        detail: studentDetailsById[student.studentId] || { address: { street: '', city: '' } }
      }));
  }, [searchText, selectedSubject]);

  const handleAddSubject = (event) => {
    event.preventDefault();
    if (!newSubjectId.trim() || !newSubjectName.trim()) return;

    const nextId = subjects.length > 0 ? Math.max(...subjects.map((item) => item.id)) + 1 : 1;
    setSubjects([
      ...subjects,
      { id: nextId, subjectId: newSubjectId.trim(), name: newSubjectName.trim() }
    ]);
    setNewSubjectId('');
    setNewSubjectName('');
  };

  return (
    <div className="container py-4">
      <h1 className="text-center mb-4">Students Management</h1>
      <div className="mb-4">
        <input
          type="text"
          className="form-control"
          placeholder="Enter student name to search ..."
          value={searchText}
          onChange={(e) => setSearchText(e.target.value)}
        />
      </div>
      <div className="row">
        <div className="col-md-4 mb-4">
          <div className="card p-3">
            <h4>Subjects</h4>
            <div className="list-group list-group-flush">
              {subjects.map((subject) => (
                <button
                  type="button"
                  key={subject.subjectId}
                  className={`list-group-item list-group-item-action text-start ${
                    selectedSubject === subject.subjectId ? 'active' : ''
                  }`}
                  onClick={() => setSelectedSubject(selectedSubject === subject.subjectId ? '' : subject.subjectId)}
                >
                  {subject.name}
                </button>
              ))}
            </div>
            <form className="mt-4" onSubmit={handleAddSubject}>
              <div className="mb-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Enter SubjectId"
                  value={newSubjectId}
                  onChange={(e) => setNewSubjectId(e.target.value)}
                />
              </div>
              <div className="mb-2">
                <input
                  type="text"
                  className="form-control"
                  placeholder="Enter SubjectName"
                  value={newSubjectName}
                  onChange={(e) => setNewSubjectName(e.target.value)}
                />
              </div>
              <button type="submit" className="btn btn-secondary">Add</button>
            </form>
            {selectedSubject && (
              <div className="mt-3 alert alert-info p-2">
                Filtering by subject: <strong>{selectedSubject}</strong>
              </div>
            )}
          </div>
        </div>
        <div className="col-md-8">
          <div className="card p-3">
            <h4>List of Students</h4>
            <div className="table-responsive">
              <table className="table table-striped table-bordered align-middle">
                <thead>
                  <tr>
                    <th>StudentId</th>
                    <th>Name</th>
                    <th>Age</th>
                    <th>Street</th>
                    <th>City</th>
                    <th>IsRegularStudent</th>
                    <th>View grades</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredStudents.length > 0 ? (
                    filteredStudents.map((student) => (
                      <tr key={student.studentId}>
                        <td>{student.studentId}</td>
                        <td>{student.name}</td>
                        <td>{student.age}</td>
                        <td>{student.detail.address.street}</td>
                        <td>{student.detail.address.city}</td>
                        <td>{student.isRegularStudent ? 'Fulltime' : 'Applicant'}</td>
                        <td>
                          <Link to={`/student/${student.studentId}`}>Grades</Link>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={7} className="text-center">
                        No students found.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
      <footer className="text-center mt-4 pt-3 border-top">
        Copyright by: HExxxxxx
      </footer>
    </div>
  );
}

function StudentDetails() {
  const { studentId } = useParams();
  const navigate = useNavigate();
  const student = database.students.find((item) => item.studentId === studentId);
  const detail = studentDetailsById[studentId];
  const evaluations = evaluationsByStudent[studentId] || [];

  if (!student) {
    return (
      <div className="container py-4">
        <div className="alert alert-warning">Student with ID {studentId} not found.</div>
        <button className="btn btn-secondary" onClick={() => navigate('/')}>Back to Home</button>
      </div>
    );
  }

  return (
    <div className="container py-4">
      <div className="mb-3">
        <button className="btn btn-success" onClick={() => navigate('/')}>Back to Home</button>
      </div>
      <div className="card p-3">
        <h4>{student.name}'s Grade Details:</h4>
        <div className="table-responsive mt-3">
          <table className="table table-striped table-bordered">
            <thead>
              <tr>
                <th>Grade</th>
                <th>Explanation</th>
              </tr>
            </thead>
            <tbody>
              {evaluations.length > 0 ? (
                evaluations.map((record) => (
                  <tr key={record.id}>
                    <td>{record.grade}</td>
                    <td>{record.additionalExplanation}</td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={2} className="text-center">No grades available.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/student/:studentId" element={<StudentDetails />} />
      </Routes>
    </Router>
  );
}

export default App;
